import type { EnrichmentState } from "@/features/enrichment/types";
import type { SavedTag } from "@/features/tags/types";

export type LinkDraftInput = {
  url: string;
  title: string;
};

export type SavedLinkSummary = {
  id: string;
  url: string;
  title: string;
  summary: string | null;
  enrichment: EnrichmentState;
  tags: SavedTag[];
  createdAt: Date;
  updatedAt: Date;
};

import "server-only";

import type { EnrichmentMetadata, MinaChatMessage } from "@/features/ai/client";
import { requestMinaEnrichment } from "@/features/ai/client";
import { normalizeEnrichmentFailure } from "@/features/enrichment/service";
import type { EnrichmentState } from "@/features/enrichment/types";

type LinkEnrichmentSource = {
  id: string;
  url: string;
  title: string;
  enrichment: Pick<EnrichmentState, "status" | "attempts">;
};

type LinkEnrichmentDependencies = {
  findSourceById(id: string): Promise<LinkEnrichmentSource | null>;
  requestMetadata(messages: MinaChatMessage[]): Promise<EnrichmentMetadata>;
  recordSuccess(id: string, expectedAttempt: number, data: EnrichmentMetadata): Promise<boolean>;
  recordFailure(id: string, expectedAttempt: number, error: string): Promise<boolean>;
};

const linkEnrichmentSystemPrompt =
  "You generate AI-owned metadata for one private saved link. Return JSON only with keys `summary` and `tags`. " +
  "Use only the provided title and URL. Do not claim to have visited the page. " +
  "The summary must be 1-2 sentences, concise, factual, and under 240 characters. " +
  "The tags array must contain 2-6 short topic tags with no duplicates.";

export function buildLinkEnrichmentMessages(link: Pick<LinkEnrichmentSource, "title" | "url">): MinaChatMessage[] {
  return [
    {
      role: "system",
      content: linkEnrichmentSystemPrompt
    },
    {
      role: "user",
      content: [`Title: ${link.title}`, `URL: ${link.url}`].join("\n\n")
    }
  ];
}

export async function executeLinkEnrichment(
  dependencies: LinkEnrichmentDependencies,
  id: string,
  expectedAttempt: number
) {
  const link = await dependencies.findSourceById(id);

  if (!link || link.enrichment.status !== "pending" || link.enrichment.attempts !== expectedAttempt) {
    return "skipped";
  }

  try {
    const metadata = await dependencies.requestMetadata(buildLinkEnrichmentMessages(link));
    await dependencies.recordSuccess(id, expectedAttempt, metadata);

    return "ready";
  } catch (error) {
    await dependencies.recordFailure(id, expectedAttempt, normalizeEnrichmentFailure(error));

    return "failed";
  }
}

export async function runLinkEnrichment(id: string, expectedAttempt: number) {
  const { linksRepo } = await import("@/features/links/repo");

  return executeLinkEnrichment(
    {
      findSourceById: linksRepo.findEnrichmentSourceById,
      requestMetadata: requestMinaEnrichment,
      recordSuccess: (linkId, attempt, data) =>
        linksRepo.recordGeneratedMetadata(linkId, attempt, {
          summary: data.summary,
          tagNames: data.tags
        }),
      recordFailure: linksRepo.recordGeneratedFailure
    },
    id,
    expectedAttempt
  );
}

import "server-only";

import type { EnrichmentRecordFields } from "@/features/enrichment/types";
import { normalizeEnrichmentStatus, toEnrichmentState } from "@/features/enrichment/types";
import { prisma } from "@/lib/prisma";

const linkTagSelect = {
  orderBy: {
    name: "asc" as const
  },
  select: {
    id: true,
    name: true
  }
};

const linkSummarySelect = {
  id: true,
  url: true,
  title: true,
  summary: true,
  enrichmentStatus: true,
  enrichmentError: true,
  enrichmentAttempts: true,
  enrichmentUpdatedAt: true,
  createdAt: true,
  updatedAt: true,
  tags: linkTagSelect
};

function mapLinkRecord<TRecord extends EnrichmentRecordFields>(link: TRecord) {
  const { enrichmentStatus, enrichmentError, enrichmentAttempts, enrichmentUpdatedAt, ...rest } = link;

  return {
    ...rest,
    enrichment: toEnrichmentState({
      enrichmentStatus,
      enrichmentError,
      enrichmentAttempts,
      enrichmentUpdatedAt
    })
  };
}

export const linksRepo = {
  async listForOwner(ownerId: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async listForOwnerByTag(ownerId: string, tagName: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId,
        tags: {
          some: {
            name: tagName
          }
        }
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async findByIdForOwner(ownerId: string, id: string) {
    const link = await prisma.link.findFirst({
      where: {
        id,
        ownerId
      },
      select: linkSummarySelect
    });

    return link ? mapLinkRecord(link) : null;
  },
  async searchForOwner(ownerId: string, query: string) {
    const links = await prisma.link.findMany({
      where: {
        ownerId,
        OR: [
          {
            title: {
              contains: query
            }
          },
          {
            url: {
              contains: query
            }
          },
          {
            tags: {
              some: {
                name: {
                  contains: query
                }
              }
            }
          }
        ]
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: linkSummarySelect
    });

    return links.map(mapLinkRecord);
  },
  async create(ownerId: string, data: { url: string; title: string }) {
    const link = await prisma.link.create({
      data: {
        ownerId,
        url: data.url,
        title: data.title
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentPending(id: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        summary: null,
        enrichmentStatus: "pending",
        enrichmentError: null,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date(),
        tags: {
          set: []
        }
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentReady(id: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        enrichmentStatus: "ready",
        enrichmentError: null,
        enrichmentUpdatedAt: new Date()
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async setEnrichmentFailed(id: string, error: string) {
    const link = await prisma.link.update({
      where: {
        id
      },
      data: {
        summary: null,
        enrichmentStatus: "failed",
        enrichmentError: error,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date(),
        tags: {
          set: []
        }
      },
      select: linkSummarySelect
    });

    return mapLinkRecord(link);
  },
  async findEnrichmentSourceById(id: string) {
    const link = await prisma.link.findUnique({
      where: {
        id
      },
      select: {
        id: true,
        url: true,
        title: true,
        enrichmentStatus: true,
        enrichmentAttempts: true
      }
    });

    if (!link) {
      return null;
    }

    return {
      id: link.id,
      url: link.url,
      title: link.title,
      enrichment: {
        status: normalizeEnrichmentStatus(link.enrichmentStatus),
        attempts: link.enrichmentAttempts
      }
    };
  },
  async recordGeneratedMetadata(id: string, expectedAttempt: number, data: { summary: string; tagNames: string[] }) {
    return prisma.$transaction(async (transaction) => {
      const link = await transaction.link.findUnique({
        where: {
          id
        },
        select: {
          enrichmentAttempts: true
        }
      });

      if (!link || link.enrichmentAttempts !== expectedAttempt) {
        return false;
      }

      await transaction.link.update({
        where: {
          id
        },
        data: {
          summary: data.summary,
          enrichmentStatus: "ready",
          enrichmentError: null,
          enrichmentUpdatedAt: new Date(),
          tags: {
            set: [],
            connectOrCreate: data.tagNames.map((name) => ({
              where: {
                name
              },
              create: {
                name
              }
            }))
          }
        }
      });

      return true;
    });
  },
  async recordGeneratedFailure(id: string, expectedAttempt: number, error: string) {
    return prisma.$transaction(async (transaction) => {
      const link = await transaction.link.findUnique({
        where: {
          id
        },
        select: {
          enrichmentAttempts: true
        }
      });

      if (!link || link.enrichmentAttempts !== expectedAttempt) {
        return false;
      }

      await transaction.link.update({
        where: {
          id
        },
        data: {
          summary: null,
          enrichmentStatus: "failed",
          enrichmentError: error,
          enrichmentUpdatedAt: new Date(),
          tags: {
            set: []
          }
        }
      });

      return true;
    });
  }
};

