import { rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import path from "node:path";

export const PLAYWRIGHT_AI_TEST_MODE_FILE =
  process.env.PLAYWRIGHT_AI_TEST_MODE_FILE ?? path.join(tmpdir(), "minakeep-playwright-ai-mode.json");

export async function setAiPlaywrightTestMode(mode: "passthrough" | "success" | "timeout") {
  if (mode === "passthrough") {
    await rm(PLAYWRIGHT_AI_TEST_MODE_FILE, { force: true });
    return;
  }

  await writeFile(PLAYWRIGHT_AI_TEST_MODE_FILE, `${JSON.stringify({ mode })}\n`, "utf8");
}

import { NextResponse } from "next/server";

import { getPlaywrightAiTestMode } from "@/features/ai/test-mode";

function isPlaywrightTestServer() {
  return process.env.PLAYWRIGHT_TEST === "1";
}

function getStubDelayMs() {
  const timeoutMs = Number.parseInt(process.env.MINA_AI_TIMEOUT_MS ?? "", 10);

  if (Number.isFinite(timeoutMs) && timeoutMs > 0) {
    return timeoutMs + 1000;
  }

  return 2500;
}

function createSuccessResponse(content: string) {
  const words = content
    .toLowerCase()
    .match(/[a-z0-9-]{4,}/g)
    ?.filter((word, index, allWords) => allWords.indexOf(word) === index)
    .filter((word) => !["http", "https", "title", "markdown"].includes(word))
    .slice(0, 3) ?? ["generated", "metadata"];

  const summarySource = content.replace(/\s+/g, " ").trim().slice(0, 120) || "the saved item";

  return {
    choices: [
      {
        message: {
          content: JSON.stringify({
            summary: `AI summary for ${summarySource}.`,
            tags: words
          })
        }
      }
    ]
  };
}

export async function POST(request: Request) {
  if (!isPlaywrightTestServer()) {
    return NextResponse.json({ error: "Not found." }, { status: 404 });
  }

  const mode = getPlaywrightAiTestMode();

  if (mode === "success") {
    const body = (await request.json().catch(() => null)) as { messages?: Array<{ role?: string; content?: string }> } | null;
    const content = body?.messages?.map((message) => message.content ?? "").join(" ").trim() ?? "";

    return NextResponse.json(createSuccessResponse(content));
  }

  await new Promise((resolve) => {
    setTimeout(resolve, getStubDelayMs());
  });

  return NextResponse.json({
    choices: [
      {
        message: {
          content: JSON.stringify({
            summary: "This response should arrive after the client timeout.",
            tags: ["timeout"]
          })
        }
      }
    ]
  });
}

import "server-only";

import { getPlaywrightAiTestBaseUrl, getPlaywrightAiTestMode } from "@/features/ai/test-mode";

export const MINA_AI_ENV_KEYS = ["LLM_BASE", "TOKEN", "MODEL"] as const;

export type RequiredAiEnv = (typeof MINA_AI_ENV_KEYS)[number];

type MinaAiConfig = {
  baseUrl: string;
  token: string;
  model: string;
};

export type MinaAiConfigStatus =
  | {
      state: "configured";
      config: MinaAiConfig;
    }
  | {
      state: "disabled";
    }
  | {
      state: "invalid";
      missing: RequiredAiEnv[];
    };

function readOptionalEnv(name: RequiredAiEnv) {
  const value = process.env[name]?.trim();

  return value ? value : null;
}

function getMissingConfig(baseUrl: string | null, token: string | null, model: string | null) {
  const missing: RequiredAiEnv[] = [];

  if (!baseUrl) {
    missing.push("LLM_BASE");
  }

  if (!token) {
    missing.push("TOKEN");
  }

  if (!model) {
    missing.push("MODEL");
  }

  return missing;
}

export function getMinaAiConfigStatus(): MinaAiConfigStatus {
  const baseUrl = readOptionalEnv("LLM_BASE");
  const token = readOptionalEnv("TOKEN");
  const model = readOptionalEnv("MODEL");
  const playwrightAiMode = getPlaywrightAiTestMode();
  const missing = getMissingConfig(baseUrl, token, model);

  if (playwrightAiMode === "success" || playwrightAiMode === "timeout") {
    return {
      state: "configured",
      config: {
        baseUrl: getPlaywrightAiTestBaseUrl(),
        token: token ?? "playwright-test-token",
        model: model ?? "playwright-test-model"
      }
    };
  }

  if (missing.length === MINA_AI_ENV_KEYS.length) {
    return {
      state: "disabled"
    };
  }

  if (missing.length > 0) {
    return {
      state: "invalid",
      missing
    };
  }

  return {
    state: "configured",
    config: {
      baseUrl: baseUrl ?? "",
      token: token ?? "",
      model: model ?? ""
    }
  };
}

import "server-only";

import { readFileSync } from "node:fs";
import { tmpdir } from "node:os";
import path from "node:path";

export const PLAYWRIGHT_AI_TEST_MODE_FILE =
  process.env.PLAYWRIGHT_AI_TEST_MODE_FILE ?? path.join(tmpdir(), "minakeep-playwright-ai-mode.json");

export type PlaywrightAiTestMode = "passthrough" | "success" | "timeout";

type StoredPlaywrightAiTestMode = {
  mode?: string;
};

function isPlaywrightTestServer() {
  return process.env.PLAYWRIGHT_TEST === "1";
}

export function getPlaywrightAiTestMode(): PlaywrightAiTestMode {
  if (!isPlaywrightTestServer()) {
    return "passthrough";
  }

  try {
    const storedMode = JSON.parse(readFileSync(PLAYWRIGHT_AI_TEST_MODE_FILE, "utf8")) as StoredPlaywrightAiTestMode;

    if (storedMode.mode === "timeout") {
      return "timeout";
    }

    if (storedMode.mode === "success") {
      return "success";
    }

    return "passthrough";
  } catch {
    return "passthrough";
  }
}

export function getPlaywrightAiTestBaseUrl() {
  const port = process.env.PLAYWRIGHT_WEB_SERVER_PORT ?? "3100";

  return `http://127.0.0.1:${port}/api/test/mina/`;
}

import "server-only";

import type { EnrichmentMetadata, MinaChatMessage } from "@/features/ai/client";
import { requestMinaEnrichment } from "@/features/ai/client";
import { normalizeEnrichmentFailure } from "@/features/enrichment/service";
import type { EnrichmentState } from "@/features/enrichment/types";

type NoteEnrichmentSource = {
  id: string;
  title: string;
  markdown: string;
  enrichment: Pick<EnrichmentState, "status" | "attempts">;
};

type NoteEnrichmentDependencies = {
  findSourceById(id: string): Promise<NoteEnrichmentSource | null>;
  requestMetadata(messages: MinaChatMessage[]): Promise<EnrichmentMetadata>;
  recordSuccess(id: string, expectedAttempt: number, data: EnrichmentMetadata): Promise<boolean>;
  recordFailure(id: string, expectedAttempt: number, error: string): Promise<boolean>;
};

const noteEnrichmentSystemPrompt =
  "You generate AI-owned metadata for one private markdown note. Return JSON only with keys `summary` and `tags`. " +
  "The summary must be 1-2 sentences, concise, factual, and under 240 characters. " +
  "The tags array must contain 2-6 short topic tags with no duplicates.";

export function buildNoteEnrichmentMessages(note: Pick<NoteEnrichmentSource, "title" | "markdown">): MinaChatMessage[] {
  return [
    {
      role: "system",
      content: noteEnrichmentSystemPrompt
    },
    {
      role: "user",
      content: [`Title: ${note.title}`, "Markdown:", note.markdown.trim() || "(empty note)"].join("\n\n")
    }
  ];
}

export async function executeNoteEnrichment(
  dependencies: NoteEnrichmentDependencies,
  id: string,
  expectedAttempt: number
) {
  const note = await dependencies.findSourceById(id);

  if (!note || note.enrichment.status !== "pending" || note.enrichment.attempts !== expectedAttempt) {
    return "skipped";
  }

  try {
    const metadata = await dependencies.requestMetadata(buildNoteEnrichmentMessages(note));
    await dependencies.recordSuccess(id, expectedAttempt, metadata);

    return "ready";
  } catch (error) {
    await dependencies.recordFailure(id, expectedAttempt, normalizeEnrichmentFailure(error));

    return "failed";
  }
}

export async function runNoteEnrichment(id: string, expectedAttempt: number) {
  const { notesRepo } = await import("@/features/notes/repo");

  return executeNoteEnrichment(
    {
      findSourceById: notesRepo.findEnrichmentSourceById,
      requestMetadata: requestMinaEnrichment,
      recordSuccess: (noteId, attempt, data) =>
        notesRepo.recordGeneratedMetadata(noteId, attempt, {
          summary: data.summary,
          tagNames: data.tags
        }),
      recordFailure: notesRepo.recordGeneratedFailure
    },
    id,
    expectedAttempt
  );
}

