  const note = await getOwnerNoteForEditor(owner.id, id);

  if (!note) {
    notFound();
  }

  return (
    <NoteEditor
      action={updateNoteAction.bind(null, note.id)}
      formDescription="Edit the note, confirm the rendered output, and explicitly choose when it should appear on the public site."
      formTitle="Edit draft note"
      enrichment={note.enrichment}
      generatedSummary={note.summary}
      generatedTags={note.tags}
      initialMarkdown={note.markdown}
      initialTitle={note.title}
      publication={{
        isPublished: note.isPublished,
        publicHref: `/notes/${note.slug}`,
        publishAction: publishNoteAction.bind(null, note.id),
        unpublishAction: unpublishNoteAction.bind(null, note.id)
      }}
      retryAction={retryNoteEnrichmentAction.bind(null, note.id)}
      savedNotice={
        resolvedSearchParams.published === "1"
          ? "Note published."
          : resolvedSearchParams.unpublished === "1"
            ? "Note unpublished."
            : resolvedSearchParams.retried === "1"
              ? "Retry requested."
            : resolvedSearchParams.saved === "1"
              ? "Draft saved."
              : undefined
      }
      submitLabel="Save draft"
    />
  );
}

"use server";

import { notFound, redirect } from "next/navigation";
import { revalidatePath } from "next/cache";
import { after } from "next/server";

import { runNoteEnrichment } from "@/features/notes/enrichment";
import {
  createDraftNote,
  publishNote,
  retryNoteEnrichment,
  startNoteEnrichment,
  unpublishNote,
  updateDraftNote
} from "@/features/notes/service";
import { requireOwnerSession } from "@/lib/auth/owner-session";

function getNoteInput(formData: FormData) {
  return {
    title: String(formData.get("title") ?? ""),
    markdown: String(formData.get("markdown") ?? "")
  };
}

function revalidateNotePaths(note: { id: string; slug: string }) {
  revalidatePath("/");
  revalidatePath("/app");
  revalidatePath("/app/search");
  revalidatePath("/app/tags");
  revalidatePath(`/app/notes/${note.id}/edit`);
  revalidatePath(`/notes/${note.slug}`);
}

function scheduleNoteEnrichment(note: { id: string; slug: string }, attempt: number) {
  after(async () => {
    await runNoteEnrichment(note.id, attempt);
    revalidateNotePaths(note);
  });
}

async function queueNoteEnrichment(note: { id: string; slug: string }) {
  const enrichedNote = await startNoteEnrichment(note.id);

  if (enrichedNote.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, enrichedNote.enrichment.attempts);
  }

  return enrichedNote;
}

export async function createNoteAction(formData: FormData) {
  const owner = await requireOwnerSession();
  const note = await createDraftNote(owner.id, getNoteInput(formData));
  await queueNoteEnrichment(note);

  revalidateNotePaths(note);
  redirect(`/app/notes/${note.id}/edit?saved=1`);
}

export async function updateNoteAction(noteId: string, formData: FormData) {
  const owner = await requireOwnerSession();
  const note = await updateDraftNote(owner.id, noteId, getNoteInput(formData));

  if (!note) {
    notFound();
  }

  await queueNoteEnrichment(note);
  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?saved=1`);
}

export async function publishNoteAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await publishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?published=1`);
}

export async function unpublishNoteAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await unpublishNote(owner.id, noteId);

  if (!note) {
    notFound();
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?unpublished=1`);
}

export async function retryNoteEnrichmentAction(noteId: string) {
  const owner = await requireOwnerSession();
  const note = await retryNoteEnrichment(owner.id, noteId);

  if (!note) {
    notFound();
  }

  if (note.enrichment.status === "pending") {
    scheduleNoteEnrichment(note, note.enrichment.attempts);
  }

  revalidateNotePaths(note);
  redirect(`/app/notes/${noteId}/edit?retried=1`);
}

"use client";

import Link from "next/link";
import { useEffect, useState } from "react";
import { useFormStatus } from "react-dom";
import { useRouter } from "next/navigation";

import type { EnrichmentState } from "@/features/enrichment/types";
import { getEnrichmentStatusDetail, getEnrichmentStatusLabel } from "@/features/enrichment/types";
import { renderMarkdownToHtml } from "@/features/notes/markdown";
import type { SavedTag } from "@/features/tags/types";

type NoteEditorProps = {
  initialTitle: string;
  initialMarkdown: string;
  action: (formData: FormData) => void | Promise<void>;
  formTitle: string;
  formDescription: string;
  submitLabel: string;
  savedNotice?: string;
  enrichment?: EnrichmentState;
  generatedSummary?: string | null;
  generatedTags?: SavedTag[];
  retryAction?: () => void | Promise<void>;
  publication?: {
    isPublished: boolean;
    publicHref: `/notes/${string}`;
    publishAction: () => void | Promise<void>;
    unpublishAction: () => void | Promise<void>;
  };
};

function SaveButton({ label }: { label: string }) {
  const { pending } = useFormStatus();

  return (
    <button className="primary-button" type="submit">
      {pending ? "Saving..." : label}
    </button>
  );
}

function PublicationButton({ idleLabel, pendingLabel }: { idleLabel: string; pendingLabel: string }) {
  const { pending } = useFormStatus();

  return (
    <button className="ghost-button" type="submit">
      {pending ? pendingLabel : idleLabel}
    </button>
  );
}

function RetryButton() {
  const { pending } = useFormStatus();

  return (
    <button className="ghost-button" type="submit">
      {pending ? "Retrying..." : "Retry AI enrichment"}
    </button>
  );
}

export function NoteEditor({
  initialTitle,
  initialMarkdown,
  action,
  formTitle,
  formDescription,
  submitLabel,
  savedNotice,
  enrichment,
  generatedSummary,
  generatedTags = [],
  retryAction,
  publication
}: NoteEditorProps) {
  const router = useRouter();
  const [title, setTitle] = useState(initialTitle);
  const [markdown, setMarkdown] = useState(initialMarkdown);
  const previewTitle = title.trim() || "Untitled note";
  const previewHtml = renderMarkdownToHtml(markdown);

  useEffect(() => {
    if (enrichment?.status !== "pending") {
      return;
    }

    const intervalId = window.setInterval(() => {
      router.refresh();
    }, 2000);

    return () => {
      window.clearInterval(intervalId);
    };
  }, [enrichment?.status, router]);

  return (
    <div className="note-editor-shell">
      <section className="panel-card note-editor-intro">
        <p className="eyebrow">Private note authoring</p>
        <h1>{formTitle}</h1>
        <p className="lede">{formDescription}</p>
        {publication ? (
          <div className="publication-panel">
            <div className="note-meta">
              <span>{publication.isPublished ? "Published" : "Private draft"}</span>
              <span>{publication.isPublished ? "Visible on public routes" : "Hidden from public routes"}</span>
            </div>
            <div className="button-row">
              {publication.isPublished ? (
                <form action={publication.unpublishAction}>
                  <PublicationButton idleLabel="Unpublish note" pendingLabel="Unpublishing..." />
                </form>
              ) : (
                <form action={publication.publishAction}>
                  <PublicationButton idleLabel="Publish note" pendingLabel="Publishing..." />
                </form>
              )}
              {publication.isPublished ? (
                <Link className="ghost-button" href={publication.publicHref}>
                  View public note
                </Link>
              ) : null}
            </div>
          </div>
        ) : null}
        {savedNotice ? <p className="status-note">{savedNotice}</p> : null}
      </section>

      {enrichment ? (
        <section className="panel-card note-generated-panel" data-testid="note-enrichment-panel">
          <p className="eyebrow">AI note metadata</p>
          <div className="note-meta">
            <span>{getEnrichmentStatusLabel(enrichment.status)}</span>
            <span>{getEnrichmentStatusDetail(enrichment)}</span>
          </div>
          <div className="note-generated-copy">
            <strong>AI summary</strong>
            {generatedSummary ? (
              <p data-testid="note-ai-summary">{generatedSummary}</p>
            ) : (
              <p className="field-note">A generated summary will appear here after a successful enrichment run.</p>
            )}
          </div>
          <div className="note-generated-copy">
            <strong>AI tags</strong>
            <div className="tag-list" data-testid="note-ai-tags">
              {generatedTags.length === 0 ? (
                <span className="tag-pill tag-pill-muted">No generated tags yet</span>
              ) : (
                generatedTags.map((tag) => (
                  <span className="tag-pill" key={tag.id}>
                    {tag.name}
                  </span>
                ))
              )}
            </div>
          </div>
          {enrichment.status === "failed" && retryAction ? (
            <form action={retryAction}>
              <RetryButton />
            </form>
          ) : null}
        </section>
      ) : null}

      <div className="note-editor-grid">
        <form action={action} className="panel-card note-form">
          <label className="field-group">
            <span>Title</span>
            <input
              autoComplete="off"
              className="text-input"
              name="title"
              onChange={(event) => setTitle(event.target.value)}
              placeholder="Draft title"
              required
              type="text"
              value={title}
            />
          </label>

          <label className="field-group note-body-field">
            <span>Markdown body</span>
            <textarea
              className="note-textarea"
              name="markdown"
              onChange={(event) => setMarkdown(event.target.value)}
              placeholder={`# Start writing

Use markdown for headings, lists, links, and code.`}
              spellCheck="true"
              value={markdown}
            />
          </label>

          <div className="button-row">
            <SaveButton label={submitLabel} />
          </div>
        </form>

        <section aria-labelledby="note-preview-heading" className="panel-card note-preview-panel">
          <p className="eyebrow">Preview</p>
          <h2 id="note-preview-heading">{previewTitle}</h2>
          <div
            className="markdown-preview"
            data-testid="note-markdown-preview"
            dangerouslySetInnerHTML={{
              __html: previewHtml || "<p>Start writing to see the rendered preview.</p>"
            }}
          />
        </section>
      </div>
    </div>
  );
}

import "server-only";

import type { EnrichmentRecordFields } from "@/features/enrichment/types";
import { normalizeEnrichmentStatus, toEnrichmentState } from "@/features/enrichment/types";
import { prisma } from "@/lib/prisma";

const noteTagSelect = {
  orderBy: {
    name: "asc" as const
  },
  select: {
    id: true,
    name: true
  }
};

const noteSummarySelect = {
  id: true,
  title: true,
  excerpt: true,
  summary: true,
  isPublished: true,
  enrichmentStatus: true,
  enrichmentError: true,
  enrichmentAttempts: true,
  enrichmentUpdatedAt: true,
  createdAt: true,
  updatedAt: true,
  tags: noteTagSelect
};

const noteEditorSelect = {
  ...noteSummarySelect,
  slug: true,
  markdown: true
};

const notePublishedSelect = {
  id: true,
  title: true,
  slug: true,
  markdown: true,
  excerpt: true,
  summary: true,
  publishedAt: true,
  updatedAt: true,
  tags: noteTagSelect
};

function mapNoteRecord<TRecord extends EnrichmentRecordFields>(note: TRecord) {
  const { enrichmentStatus, enrichmentError, enrichmentAttempts, enrichmentUpdatedAt, ...rest } = note;

  return {
    ...rest,
    enrichment: toEnrichmentState({
      enrichmentStatus,
      enrichmentError,
      enrichmentAttempts,
      enrichmentUpdatedAt
    })
  };
}

export const notesRepo = {
  async listForOwner(ownerId: string) {
    const notes = await prisma.note.findMany({
      where: {
        ownerId
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: noteSummarySelect
    });

    return notes.map(mapNoteRecord);
  },
  async listForOwnerByTag(ownerId: string, tagName: string) {
    const notes = await prisma.note.findMany({
      where: {
        ownerId,
        tags: {
          some: {
            name: tagName
          }
        }
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: noteSummarySelect
    });

    return notes.map(mapNoteRecord);
  },
  async searchForOwner(ownerId: string, query: string) {
    const notes = await prisma.note.findMany({
      where: {
        ownerId,
        OR: [
          {
            title: {
              contains: query
            }
          },
          {
            tags: {
              some: {
                name: {
                  contains: query
                }
              }
            }
          }
        ]
      },
      orderBy: {
        updatedAt: "desc"
      },
      select: noteSummarySelect
    });

    return notes.map(mapNoteRecord);
  },
  async listPublished() {
    return prisma.note.findMany({
      where: {
        isPublished: true
      },
      orderBy: [
        {
          publishedAt: "desc"
        },
        {
          updatedAt: "desc"
        }
      ],
      select: {
        id: true,
        title: true,
        slug: true,
        excerpt: true,
        summary: true,
        publishedAt: true,
        updatedAt: true,
        tags: noteTagSelect
      }
    });
  },
  async findByIdForOwner(ownerId: string, id: string) {
    const note = await prisma.note.findFirst({
      where: {
        id,
        ownerId
      },
      select: noteEditorSelect
    });

    return note ? mapNoteRecord(note) : null;
  },
  async findPublishedBySlug(slug: string) {
    return prisma.note.findFirst({
      where: {
        slug,
        isPublished: true
      },
      select: notePublishedSelect
    });
  },
  async listSlugsForOwner(ownerId: string) {
    const notes = await prisma.note.findMany({
      where: {
        ownerId
      },
      select: {
        slug: true
      }
    });

    return notes.map((note) => note.slug);
  },
  async create(ownerId: string, data: { title: string; slug: string; markdown: string; excerpt: string }) {
    const note = await prisma.note.create({
      data: {
        ownerId,
        title: data.title,
        slug: data.slug,
        markdown: data.markdown,
        excerpt: data.excerpt
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async update(id: string, data: { title: string; slug: string; markdown: string; excerpt: string }) {
    const note = await prisma.note.update({
      where: {
        id
      },
      data: {
        title: data.title,
        slug: data.slug,
        markdown: data.markdown,
        excerpt: data.excerpt
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async updatePublication(id: string, isPublished: boolean) {
    const note = await prisma.note.update({
      where: {
        id
      },
      data: {
        isPublished,
        publishedAt: isPublished ? new Date() : null
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async setEnrichmentPending(id: string) {
    const note = await prisma.note.update({
      where: {
        id
      },
      data: {
        summary: null,
        enrichmentStatus: "pending",
        enrichmentError: null,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date(),
        tags: {
          set: []
        }
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async setEnrichmentReady(id: string) {
    const note = await prisma.note.update({
      where: {
        id
      },
      data: {
        enrichmentStatus: "ready",
        enrichmentError: null,
        enrichmentUpdatedAt: new Date()
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async setEnrichmentFailed(id: string, error: string) {
    const note = await prisma.note.update({
      where: {
        id
      },
      data: {
        summary: null,
        enrichmentStatus: "failed",
        enrichmentError: error,
        enrichmentAttempts: {
          increment: 1
        },
        enrichmentUpdatedAt: new Date(),
        tags: {
          set: []
        }
      },
      select: noteEditorSelect
    });

    return mapNoteRecord(note);
  },
  async findEnrichmentSourceById(id: string) {
    const note = await prisma.note.findUnique({
      where: {
        id
      },
      select: {
        id: true,
        title: true,
        markdown: true,
        enrichmentStatus: true,
        enrichmentAttempts: true
      }
    });

    if (!note) {
      return null;
    }

    return {
      id: note.id,
      title: note.title,
      markdown: note.markdown,
      enrichment: {
        status: normalizeEnrichmentStatus(note.enrichmentStatus),
        attempts: note.enrichmentAttempts
      }
    };
  },
  async recordGeneratedMetadata(id: string, expectedAttempt: number, data: { summary: string; tagNames: string[] }) {
    return prisma.$transaction(async (transaction) => {
      const note = await transaction.note.findUnique({
        where: {
          id
        },
        select: {
          enrichmentAttempts: true

          enrichmentAttempts: true
        }
      });

      if (!note || note.enrichmentAttempts !== expectedAttempt) {
        return false;
      }

      await transaction.note.update({
        where: {
          id
        },
        data: {
          summary: data.summary,
          enrichmentStatus: "ready",
          enrichmentError: null,
          enrichmentUpdatedAt: new Date(),
          tags: {
            set: [],
            connectOrCreate: data.tagNames.map((name) => ({
              where: {
                name
              },
              create: {
                name
              }
            }))
          }
        }
      });

      return true;
    });
  },
  async recordGeneratedFailure(id: string, expectedAttempt: number, error: string) {
    return prisma.$transaction(async (transaction) => {
      const note = await transaction.note.findUnique({
        where: {
          id
        },
        select: {
          enrichmentAttempts: true
        }
      });

      if (!note || note.enrichmentAttempts !== expectedAttempt) {
        return false;
      }

      await transaction.note.update({
        where: {
          id
        },
        data: {
          summary: null,
          enrichmentStatus: "failed",
          enrichmentError: error,
          enrichmentUpdatedAt: new Date(),
          tags: {
            set: []
          }
        }
      });

      return true;
    });
  }
};

